import { createSmartAccountClient } from "permissionless";
import { toSimpleSmartAccount, to7702SimpleSmartAccount } from "permissionless/accounts";
import { createPimlicoClient } from "permissionless/clients/pimlico";
import {
  wrapProviderError,
  ensureExternalWalletChain,
  resolveSigner,
  rejectExternalWallet7702,
  assertAccountAddress
} from "@getpara/viem-v2-integration/aa";
import { createPublicClient, http } from "viem";
import { entryPoint07Address, entryPoint08Address, prepareUserOperation } from "viem/account-abstraction";
function buildPimlicoRpcUrl(chain, apiKey) {
  const chainSlug = chain.name.toLowerCase().replace(/\s+/g, "-");
  return `https://api.pimlico.io/v2/${chainSlug}/rpc?apikey=${apiKey}`;
}
async function createPimlicoSmartAccount(params) {
  const { para, apiKey, chain, rpcUrl, mode: rawMode = "4337" } = params;
  const mode = rawMode;
  if (mode === "7702") rejectExternalWallet7702(params.signer, "PIMLICO");
  const viemAccount = resolveSigner(para, params);
  if (!viemAccount) return null;
  const publicClient = createPublicClient({ chain, transport: http(rpcUrl) });
  const pimlicoRpcUrl = buildPimlicoRpcUrl(chain, apiKey);
  const paymasterClient = createPimlicoClient({
    entryPoint: mode === "7702" ? { address: entryPoint08Address, version: "0.8" } : { address: entryPoint07Address, version: "0.7" },
    transport: http(pimlicoRpcUrl)
  });
  let smartAccount;
  switch (mode) {
    case "7702":
      smartAccount = await to7702SimpleSmartAccount({
        client: publicClient,
        owner: viemAccount,
        entryPoint: {
          address: entryPoint08Address,
          version: "0.8"
        }
      });
      smartAccount.isDeployed = async () => false;
      break;
    case "4337":
    default:
      smartAccount = await toSimpleSmartAccount({
        client: publicClient,
        owner: viemAccount,
        entryPoint: {
          address: entryPoint07Address,
          version: "0.7"
        }
      });
      break;
  }
  const smartAccountClient = createSmartAccountClient({
    account: smartAccount,
    chain,
    paymaster: paymasterClient,
    bundlerTransport: http(pimlicoRpcUrl),
    userOperation: {
      estimateFeesPerGas: async () => {
        const gasPrice = await paymasterClient.getUserOperationGasPrice();
        return gasPrice.fast;
      },
      ...mode === "7702" && {
        prepareUserOperation: async (client, args) => {
          const prepared = await prepareUserOperation(client, args);
          if (prepared.authorization && viemAccount.signAuthorization) {
            const signedAuth = await viemAccount.signAuthorization({
              contractAddress: prepared.authorization.address,
              chainId: prepared.authorization.chainId,
              nonce: prepared.authorization.nonce
            });
            prepared.authorization = signedAuth;
          }
          return prepared;
        }
      }
    }
  });
  assertAccountAddress(smartAccountClient.account?.address, "Pimlico client", "PIMLICO");
  const waitForReceipt = async (hash) => {
    if ("waitForTransactionReceipt" in smartAccountClient && typeof smartAccountClient.waitForTransactionReceipt === "function") {
      return smartAccountClient.waitForTransactionReceipt({ hash });
    }
    return publicClient.getTransactionReceipt({ hash });
  };
  const sendBatchTransaction = async (calls) => {
    await ensureExternalWalletChain(params.signer, chain, "PIMLICO");
    try {
      const hash = await smartAccountClient.sendTransaction({
        account: smartAccountClient.account,
        calls
      });
      return waitForReceipt(hash);
    } catch (error) {
      throw wrapProviderError(error, "PIMLICO");
    }
  };
  const sendTransaction = async (tx) => sendBatchTransaction([tx]);
  return {
    smartAccountAddress: smartAccountClient.account.address,
    signer: viemAccount,
    chain,
    mode,
    provider: "PIMLICO",
    sendTransaction,
    sendBatchTransaction,
    client: smartAccountClient
  };
}
export {
  buildPimlicoRpcUrl,
  createPimlicoSmartAccount
};
